from typing import Union

def evaluate_expression(expression: str) -> Union[int, float]:
    """
    Safely evaluate a mathematical expression string.
    Supports: +, -, *, /, //, %, **, parentheses, and numbers.
    """
    # Remove whitespace
    expression = expression.replace(" ", "")

    # Parse and evaluate using ast.literal_eval with operator support
    try:
        node = ast.parse(expression, mode='eval')
        return _safe_eval(node.body)
    except (SyntaxError, ValueError, TypeError) as e:
        raise ValueError(f"Invalid expression: {e}")

def _safe_eval(node):
    """Recursively evaluate an AST node safely."""
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n
    elif isinstance(node, ast.BinOp):
        left = _safe_eval(node.left)
        right = _safe_eval(node.right)
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
        }
        op_type = type(node.op)
        if op_type not in ops:
            raise ValueError(f"Unsupported operator: {op_type}")
        return ops[op_type](left, right)
    elif isinstance(node, ast.UnaryOp):
        operand = _safe_eval(node.operand)
        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError(f"Unsupported unary operator: {type(node.op)}")
    else:
        raise ValueError(f"Unsupported expression type: {type(node)}")

